scwin.onpageload = async function () {
  let e = await $c.sbm.execute($p, sbm_lobran);
  if (e.responseJSON.GAUCE.length > 0) {
    // asis에 있어서 추가함
    ds_lobran.setRowJSON(ds_lobran.getTotalRow(), {
      "lobranCd": "ZZZ",
      "lobranNm": "미사용점소"
    });
  }
  await scwin.f_getOilStatNm();
  ds_QueryCondition.set("fromWrkDt", scwin.dateStr.substring(0, 4) + scwin.dateStr.substring(4, 6) + "01");
  ds_QueryCondition.set("toWrkDt", scwin.dateStr);
  const param = [{
    method: "getLuxeComboDataNoSort",
    param1: "PsCommonEBC",
    param2: "retriveClntCdY",
    compID: "acb_oilStatCd"
  }];
  $c.data.setGauceUtil($p, param, function () {
    scwin.onLoad = true;
  });
};
scwin.onUdcCompleted = async function () {
  while (!scwin.onLoad) {
    await new Promise(resolve => setTimeout(resolve, 50));
  }
  lc_assgnLobranCd.setValue(scwin.memJson.loUpperLobranCd);
  acb_oilStatCd.setSelectedIndex(39); // <param name=Index value=39>
};

