scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_search);
  ds_QueryCondition.set("fromWrkDt", scwin.dateStr.substring(0, 4) + scwin.dateStr.substring(4, 6) + "01");
  ds_QueryCondition.set("toWrkDt", scwin.dateStr);
  lc_assgnLobranCd.focus();
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
  } else {
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};
scwin.f_openCommonPopUp = async function (disGubun, pWinCloseTF) {
  // 선언부
  var sWinCloseTF = pWinCloseTF == null ? "T" : pWinCloseTF;
  var rtnList = new Array(); // 공통POP-UP -> 요청화면 
  var pSelectID = "";
  var pCode = "";
  var pName = "";
  var pWtitleSearch = "";
  var arrParam = new Array();
  var pLobranCd = "";
  var pLobranNm = "";
  pLobranCd = lc_assgnLobranCd.getValue(); //점소코드 

  switch (disGubun) {
    case 1:
      scwin.openPopup = false;
      // 중기 팝업	
      pCode = ed_eqCd.getValue().replace(/\s*$/, ''); // 중기코드
      pName = ed_eqNm.getValue(); // 중기명
      pDate = ed_serFromDate.getValue(); // 작업일자

      arrParam[0] = pLobranCd; //assgnLobranCd점소코드
      arrParam[1] = ""; //eqKndCd중기종류
      arrParam[2] = ""; //clntCd거래처코드
      arrParam[3] = pDate; //usblDt작업계획일자
      arrParam[4] = pCode; //eqNo
      arrParam[5] = pName; //eqNm 중기명 파라미터 넘어가도록 개선 (26.04.23)
      arrParam[6] = sWinCloseTF; //T,F구분
      arrParam[7] = 'T'; //T,F구분

      var opts = {
        id: "smpPop",
        popupName: "중기조회",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600
      };
      rtnList = await $c.win.openPopup($p, "/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml", opts, arrParam);
      if (rtnList != null && rtnList[0] != "N/A" && rtnList[0] != "undefind" && rtnList.length > 0) {
        scwin.hd_eqCd = rtnList[12]; //중기코드
        ed_eqCd.setValue(rtnList[0]); //중기단축코드

        if (rtnList[1] == "undefind" || rtnList[1].trim() == null || rtnList[1].trim() == "") {
          ed_eqNm.setValue(rtnList[2]); //중기명
        } else {
          ed_eqNm.setValue(rtnList[1]); //중기번호
        }
      } else {
        scwin.hd_eqCd = ""; //중기코드
        ed_eqCd.setValue(""); //중기단축코드
        ed_eqNm.setValue(""); //중기명					
      }
      break;
  }
};

