scwin.f_chkOpenCommonPopupText = function (inObj, codeObj, disGubun) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우
  if (inObj.getValue().trim() == "" /*|| inObj.readOnly*/) {
    return;
  }

  /*
  if (codeObj.tagName == "OBJECT") {
      codeObj.Text = "";
  } else {
      codeObj.value = "";
  }
  */

  scwin.f_openCommonPopUp(disGubun);
};

//-------------------------------------------------------------------------
// EMEDIT 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopupEmedit = function (inObj, chkObj, txtObj, disGubun) {
  var objValue = inObj.getValue().replace(/^\s*/, '');

  // if (txtObj != null) {
  //     txtObj.setValue("");
  // }

  if (txtObj == "" || txtObj == null) {
    txtObj.setValue("");
    if (chkObj != null) {
      chkObj = "";
      return;
    }
  }

  // 값이 입력이 안된 경우  팝업을 실행하지 않음.
  if (objValue == "" || objValue == null) {
    inObj.setValue("");
    if (chkObj != null) {
      chkObj = "";
      return;
    }
  }

  // 해당 EMEDIT가 Disable 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if ((/*inObj.ReadOnly || !inObj.Enable ||*/chkObj != null && objValue == chkObj)) {
    return;
  }
  scwin.f_openCommonPopUp(disGubun);
};

//-------------------------------------------------------------------------
// 중기 투입실적 및 주유소모량 
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (!(await $c.gus.cfValidate($p, [ed_serFromDate, ed_serToDate]))) {
    // 필수조건 : 중기코드, 작업일자
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_serFromDate.getValue(), ed_serToDate.getValue())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ed_srchFromDate.focus(); // ASIS 코드 그대로인데 ed_serFromDate 오탈자로 추정됨
    return;
  }
  ds_QueryCondition.set("lobranCd", lc_assgnLobranCd.getValue()); //물류점소코드
  ds_QueryCondition.set("fromWrkDt", ed_serFromDate.getValue()); //조회시작일자
  ds_QueryCondition.set("toWrkDt", ed_serToDate.getValue()); //조회종료일자
  ds_QueryCondition.set("vehclShortCd", ed_eqCd.getValue()); //장비번호
  ds_QueryCondition.set("eqCd", scwin.hd_eqCd); //EQ_CD
  ds_QueryCondition.set("posnClsCd", lc_posnClsCd.getValue()); //소유구분
  ds_QueryCondition.set("oilStatCd", acb_oilStatCd.getValue()); //소유구분

  $c.sbm.execute($p, sbm_RetrieveWorkResult);

  // gr_RetrieveWorkResult.ColumnProp('eqKndNm', 'SubSumText')='소계';  ??
  ds_RetrieveSubWorkResult.setColumnDefaultValue("eqKndNm", "소계");
};

// 차량별 주유량 등록  
scwin.f_saveOiling = async function () {
  var stdYm = "";
  var oilStatClntNo = "";
  var oilStatClntNm = "";
  scwin.f_retrieveSave();
  for (i = 0; i < ds_RetrieveSubWorkResult.getTotalRow(); i++) {
    if (!$c.gus.cfIsNull($p, ds_RetrieveSubWorkResult.getCellData(i, "clntNm")) && oilStatClntNm != ds_RetrieveSubWorkResult.getCellData(i, "clntNm")) {
      var wrkYm = ds_RetrieveSubWorkResult.getCellData(i, "wrkDt").substring(0, 6);
      oilStatClntNo = ds_RetrieveSubWorkResult.getCellData(i, "clntNo");
      oilStatClntNm = ds_RetrieveSubWorkResult.getCellData(i, "clntNm");
      var JobYn = await udc_closeYn.cfJobCloseYN("CUR", wrkYm, "00", "TR25", oilStatClntNo, null, "N"); // 집계생성 마감체크(월,재고집계,거래처)			

      if (JobYn == "0" || JobYn == "2") {
        await $c.gus.cfAlertMsg($p, oilStatClntNm + " 주유소는 해당월 마감처리 되었습니다. \n저장할 수 없습니다.");
        return;
      }
    }
  }
  if (await $c.win.confirm($p, "주유량  마감을 하시겠습니까?")) {
    $c.sbm.execute($p, sbm_save);
  }
};
